// RegisterTools registers all API operations as MCP tools.
func RegisterTools(s *server.MCPServer) {
	s.AddTool(
		mcplib.NewTool("checkout_create_checkout",
			mcplib.WithDescription("POST /checkout. Optional: version, spec, schema (plus 4 more)."),
			mcplib.WithString("version", mcplib.Description("The version parameter")),
			mcplib.WithString("spec", mcplib.Description("The spec parameter")),
			mcplib.WithString("schema", mcplib.Description("The schema parameter")),
			mcplib.WithString("id", mcplib.Description("The id parameter")),
			mcplib.WithString("config", mcplib.Description("The config parameter")),
			mcplib.WithString("transport", mcplib.Description("The transport parameter")),
			mcplib.WithString("endpoint", mcplib.Description("The endpoint parameter")),
			mcplib.WithDestructiveHintAnnotation(false),
			mcplib.WithOpenWorldHintAnnotation(true),
		),
		makeAPIHandler("POST", "/checkout", false, false, nil, []mcpParamBinding{{PublicName: "version", WireName: "version", Location: "body"}, {PublicName: "spec", WireName: "spec", Location: "body"}, {PublicName: "schema", WireName: "schema", Location: "body"}, {PublicName: "id", WireName: "id", Location: "body"}, {PublicName: "config", WireName: "config", Location: "body"}, {PublicName: "transport", WireName: "transport", Location: "body"}, {PublicName: "endpoint", WireName: "endpoint", Location: "body"}}, []string{}),
	)

	// Context tool — front-loaded domain knowledge for agents.
	// Call this first to understand the API taxonomy, query patterns, and capabilities.
	s.AddTool(
		mcplib.NewTool("context",
			mcplib.WithDescription("Get API domain context: resource taxonomy, auth requirements, query tips, and unique capabilities. Call this first."),
			mcplib.WithReadOnlyHintAnnotation(true),
			mcplib.WithDestructiveHintAnnotation(false),
		),
		handleContext,
	)

	// Runtime Cobra-tree mirror — exposes every user-facing command that is
	// not already covered by a typed endpoint or framework MCP tool.
	cobratree.RegisterAll(s, cli.RootCmd(), cobratree.SiblingCLIPath)
}

